1	// Playwright smoke test for ddx-9ce6842a AC §8.
2	//
3	// These tests measure wall-clock time from page.goto to "list is
4	// interactive" against a mocked GraphQL layer that returns a realistic-
5	// sized payload (50 beads — the default page window). They are ceilings,
6	// not p95 targets: the gate catches outright regressions (runaway render
7	// loops, missing virtualization, blocking scripts) without tying the
8	// repo's green/red status to machine speed.
9	//
10	// The matching server-side ceilings (GraphQL response under the same
11	// budget on the real fixture) are enforced in
12	// cli/internal/server/perf/smoke_test.go — together they guard the full
13	// round-trip the user feels.
14	import { expect, test } from '@playwright/test';
15	
16	const NODE_INFO = { id: 'node-smoke', name: 'smoke node' };
17	const PROJECT_ID = 'proj-smoke';
18	const PROJECTS = [{ id: PROJECT_ID, name: 'Smoke project', path: '/repos/smoke' }];
19	
20	function generateBeads(count: number) {
21		const beads = [];
22		for (let i = 0; i < count; i++) {
23			beads.push({
24				id: `ddx-smoke-${String(i).padStart(4, '0')}`,
25				title: `Smoke fixture bead ${i}`,
26				status: i % 3 === 0 ? 'closed' : 'open',
27				priority: i % 4,
28				labels: ['smoke', `bucket-${i % 7}`]
29			});
30		}
31		return beads;
32	}
33	
34	async function mockSmokeGraphQL(page: import('@playwright/test').Page, beadCount: number) {
35		const beads = generateBeads(beadCount);
36		await page.route('/graphql', async (route) => {
37			const body = route.request().postDataJSON() as { query: string };
38			if (body.query.includes('NodeInfo')) {
39				await route.fulfill({
40					status: 200,
41					contentType: 'application/json',
42					body: JSON.stringify({ data: { nodeInfo: NODE_INFO } })
43				});
44			} else if (body.query.includes('Projects')) {
45				await route.fulfill({
46					status: 200,
47					contentType: 'application/json',
48					body: JSON.stringify({
49						data: { projects: { edges: PROJECTS.map((p) => ({ node: p })) } }
50					})
51				});
52			} else if (body.query.includes('BeadsByProject') || body.query.includes('beadsByProject')) {
53				await route.fulfill({
54					status: 200,
55					contentType: 'application/json',
56					body: JSON.stringify({
57						data: {
58							beadsByProject: {
59								edges: beads.map((b, i) => ({ node: b, cursor: `cursor-${i}` })),
60								pageInfo: { hasNextPage: false, endCursor: null },
61								totalCount: beads.length
62							}
63						}
64					})
65				});
66			} else if (body.query.includes('query Beads(') || body.query.includes('Beads(')) {
67				// Cross-project list fetches the `beads` field.
68				await route.fulfill({
69					status: 200,
70					contentType: 'application/json',
71					body: JSON.stringify({
72						data: {
73							beads: {
74								edges: beads.map((b, i) => ({ node: b, cursor: `cursor-${i}` })),
75								pageInfo: { hasNextPage: false, endCursor: null },
76								totalCount: beads.length
77							}
78						}
79					})
80				});
81			} else {
82				await route.continue();
83			}
84		});
85	}
86	
87	// ddx-9ce6842a AC §8: per-project /beads interactive within 1s.
88	test('smoke: /beads list is interactive within 1s on 50-bead fixture', async ({ page }) => {
89		await mockSmokeGraphQL(page, 50);
90	
91		const start = Date.now();
92		await page.goto(`/nodes/${NODE_INFO.id}/projects/${PROJECT_ID}/beads`);
93		// "Interactive" = the heading has rendered AND at least one bead row is
94		// visible (so clicking it would navigate). Both are prerequisites to a
95		// real user clicking anything.
96		await expect(page.getByRole('heading', { name: 'Beads' })).toBeVisible({ timeout: 1000 });
97		await expect(page.getByText('Smoke fixture bead 0')).toBeVisible({ timeout: 1000 });
98		const elapsed = Date.now() - start;
99		expect(elapsed, `per-project /beads interactive in ${elapsed}ms (ceiling 1000ms)`).toBeLessThan(
100			1000
101		);
102	});
103	
104	// ddx-9ce6842a AC §8: cross-project /beads interactive within 2s.
105	// We drive the same list view with 300 rows to mimic the cross-project
106	// aggregate load — the backend ceiling is wider (2s) because the real call
107	// is beads() with no projectID.
108	test('smoke: cross-project /beads list is interactive within 2s on 300-bead fixture', async ({
109		page
110	}) => {
111		await mockSmokeGraphQL(page, 300);
112	
113		const start = Date.now();
114		await page.goto(`/nodes/${NODE_INFO.id}/projects/${PROJECT_ID}/beads`);
115		await expect(page.getByRole('heading', { name: 'Beads' })).toBeVisible({ timeout: 2000 });
116		await expect(page.getByText('Smoke fixture bead 0')).toBeVisible({ timeout: 2000 });
117		const elapsed = Date.now() - start;
118		expect(elapsed, `cross-project /beads interactive in ${elapsed}ms (ceiling 2000ms)`).toBeLessThan(
119			2000
120		);
121	});
